import argparse
import json
from pathlib import Path
from PIL import Image

IMAGE_SIZE = 256


def find_object_dirs(data_path: str):
    root = Path(data_path)
    if (root / 'input.png').exists() and (root / 'cameras.json').exists():
        return [root]
    candidates = [root / 'test', root / 'test_gt', root / 'test_hidden', root / 'eval', root / 'val', root]
    for base in candidates:
        if not base.exists() or not base.is_dir():
            continue
        objs = sorted(p for p in base.iterdir() if p.is_dir() and (p / 'input.png').exists() and (p / 'cameras.json').exists())
        if objs:
            return objs
    return []


def load_cameras(obj_dir: Path):
    try:
        cams = json.loads((obj_dir / 'cameras.json').read_text())
        return {int(c.get('view_id', i)): c for i, c in enumerate(cams)}
    except Exception:
        return {}


def load_view_ids(obj_dir: Path):
    cams = load_cameras(obj_dir)
    if cams:
        ids = sorted(k for k in cams.keys() if k != 0)
        if ids:
            return ids
    return list(range(1, 12))


def wrap_delta(a, b):
    return abs(((float(a) - float(b) + 180.0) % 360.0) - 180.0)


def load_config():
    path = Path('transform_config.json')
    if not path.exists():
        return {'mode': 'copy', 'view_map': {}, 'bins': []}
    try:
        return json.loads(path.read_text())
    except Exception:
        return {'mode': 'copy', 'view_map': {}, 'bins': []}


def choose_transform(cfg, vid, cams):
    mode = cfg.get('mode', 'copy')
    if mode == 'view_map':
        return cfg.get('view_map', {}).get(str(vid), 'copy')
    if mode == 'az_bins':
        try:
            az0 = cams.get(0, {}).get('azimuth', 0.0)
            az = cams.get(int(vid), {}).get('azimuth', az0)
            d = wrap_delta(az, az0)
            for lo, hi, name in cfg.get('bins', []):
                if (float(lo) <= d < float(hi)) or (float(hi) == 180.0 and float(lo) <= d <= 180.0):
                    return name
        except Exception:
            return 'copy'
    return 'copy'


def input_to_rgba_256(path: Path) -> Image.Image:
    img = Image.open(path).convert('RGBA')
    if img.size != (IMAGE_SIZE, IMAGE_SIZE):
        img = img.resize((IMAGE_SIZE, IMAGE_SIZE), Image.Resampling.LANCZOS)
    return img


def apply_transform(img: Image.Image, name: str):
    if name == 'hflip':
        return img.transpose(Image.Transpose.FLIP_LEFT_RIGHT)
    return img


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=False, default='')
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    cfg = load_config()
    output_path = Path(args.output)
    renders_dir = Path(str(output_path.with_suffix('')) + '_renders')
    renders_dir.mkdir(parents=True, exist_ok=True)

    obj_dirs = find_object_dirs(args.data_path)
    if not obj_dirs:
        raise RuntimeError(f'No object directories with input.png and cameras.json found under {args.data_path}')

    for obj_dir in obj_dirs:
        obj_uid = obj_dir.name
        out_obj = renders_dir / obj_uid
        out_obj.mkdir(parents=True, exist_ok=True)
        rgba = input_to_rgba_256(obj_dir / 'input.png')
        cams = load_cameras(obj_dir)
        for vid in load_view_ids(obj_dir):
            if vid == 0:
                continue
            name = choose_transform(cfg, vid, cams)
            pred = apply_transform(rgba, name)
            pred.save(out_obj / f'view_{vid:02d}.png')

    output_path.parent.mkdir(parents=True, exist_ok=True)
    with output_path.open('w') as f:
        json.dump({'predictions_dir': str(renders_dir)}, f)


if __name__ == '__main__':
    main()
